const keywordItems = $('Read Keywords').all();
const configItems = $('Read Research Config').all();
const crypto = require('crypto');

// Extract competitor URLs from research config
const competitors = configItems.filter(i => i.json.Type === 'competitor').map(c => ({ key: c.json.Key, url: c.json.URL, label: c.json.Label }));
const rssFeeds = configItems.filter(i => i.json.Type === 'rss_feed').map(r => ({ key: r.json.Key, url: r.json.URL, label: r.json.Label }));

// Scrape competitor pages
const competitorResults = [];
for (const comp of competitors.slice(0, 5)) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET', url: comp.url, timeout: 10000,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; AnyVisionBot/1.0)' },
      returnFullResponse: true
    });
    const html = typeof response === 'string' ? response : (response.body || '');
    const text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 2000);
    competitorResults.push({ source: comp.label, content: text, success: true });
  } catch(e) {
    competitorResults.push({ source: comp.label, content: `Failed: ${e.message}`, success: false });
  }
  await new Promise(r => setTimeout(r, 2000));
}

// Parse RSS feeds
const rssResults = [];
for (const feed of rssFeeds.slice(0, 5)) {
  try {
    const xml = await this.helpers.httpRequest({ method: 'GET', url: feed.url, timeout: 10000 });
    const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
    const titleRegex = /<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i;
    let match, count = 0;
    while ((match = itemRegex.exec(xml)) !== null && count < 5) {
      const title = (titleRegex.exec(match[1]) || [])[1] || '';
      rssResults.push({ source: feed.label, title: title.trim(), success: true });
      count++;
    }
  } catch(e) {
    rssResults.push({ source: feed.label, title: `Failed: ${e.message}`, success: false });
  }
  await new Promise(r => setTimeout(r, 1000));
}

// Build keywords list for SERP query
const keywords = keywordItems.map(k => k.json.Keyword || k.json.Label || '').filter(Boolean);

return {
  json: {
    competitorData: competitorResults,
    rssData: rssResults,
    keywords: keywords.slice(0, 20),
    serpQuery: keywords.slice(0, 5).join(' OR '),
    totalSources: competitorResults.length + rssResults.length
  }
};

