const input = $input.first().json;
const trendData = $('Scrape Trends').first().json;
const config = $('System Config').first().json;

let analysis;
try {
  const content = input.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  analysis = {
    clusters: [{ name: 'AI automation', keywords: ['ai automation', 'workflow automation'], intent: 'informational', difficulty: 50, opportunity: 60, volume_estimate: 'medium', recommended_content_type: 'blog' }],
    quick_wins: [{ keyword: 'n8n automation south africa', difficulty: 25, opportunity: 75, suggested_action: 'Create targeted landing page' }],
    trends: [{ trend: 'AI adoption growing in SA SMBs', relevance: 8, timeframe: 'rising' }],
    summary: 'Fallback analysis: AI automation remains a growing opportunity in South Africa.'
  };
}

// Build keyword records for upsert
const keywordRecords = [];
for (const cluster of (analysis.clusters || [])) {
  for (const kw of (cluster.keywords || [])) {
    keywordRecords.push({
      keyword: kw,
      cluster: cluster.name,
      intent: cluster.intent,
      difficulty: cluster.difficulty,
      opportunity: cluster.opportunity,
      volume: cluster.volume_estimate,
      contentType: cluster.recommended_content_type
    });
  }
}

return {
  json: {
    analysis: analysis,
    keywordRecords: keywordRecords,
    serpRawCount: (input.items || []).length,
    tokensUsed: input.usage ? input.usage.total_tokens : 0,
    week: config.weekNumber,
    date: config.todayDate
  }
};

const data = $input.first().json;
const records = data.keywordRecords || [];
if (records.length === 0) {
  return { json: { Keyword: 'no-keywords-found', Cluster: 'none', Intent: 'none', Difficulty: 0, Opportunity: 0, Volume: 'none', 'Content Type': 'none', Status: 'Active', 'Last Updated': data.date } };
}
return records.map(r => ({
  json: {
    Keyword: r.keyword,
    Cluster: r.cluster,
    Intent: r.intent,
    Difficulty: r.difficulty,
    Opportunity: r.opportunity,
    Volume: r.volume,
    'Content Type': r.contentType,
    Status: 'Active',
    'Last Updated': data.date
  }
}));

const data = $('Parse Clustering').first().json;
const analysis = data.analysis || {};
const now = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });

const clustersHtml = (analysis.clusters || []).map(c =>
  `<li><strong>${c.name}</strong> (${c.intent}) - Difficulty: ${c.difficulty}, Opportunity: ${c.opportunity}<br>Keywords: ${(c.keywords || []).join(', ')}</li>`
).join('\n');

const winsHtml = (analysis.quick_wins || []).map(w =>
  `<li><strong>${w.keyword}</strong> - Difficulty: ${w.difficulty}, Opportunity: ${w.opportunity}<br>${w.suggested_action}</li>`
).join('\n');

const trendsHtml = (analysis.trends || []).map(t =>
  `<li>${t.trend} (relevance: ${t.relevance}/10, ${t.timeframe})</li>`
).join('\n');

return {
  json: {
    subject: `SEO Keyword Discovery: ${(analysis.clusters || []).length} clusters, ${(analysis.quick_wins || []).length} quick wins`,
    body: [
      '<h2 style="color:#FF6D5A">Trend & Keyword Discovery Report</h2>',
      `<p><strong>Date:</strong> ${now}</p>`,
      `<p><strong>Sources analyzed:</strong> ${data.serpRawCount || 0} SERP results</p>`,
      '<hr>',
      `<p><em>${analysis.summary || 'No summary available'}</em></p>`,
      '<h3>Keyword Clusters</h3>',
      `<ul>${clustersHtml || '<li>None identified</li>'}</ul>`,
      '<h3>Quick Wins</h3>',
      `<ul>${winsHtml || '<li>None identified</li>'}</ul>`,
      '<h3>Trends</h3>',
      `<ul>${trendsHtml || '<li>None identified</li>'}</ul>`,
      '<hr>',
      `<p><strong>Tokens Used:</strong> ${(data.tokensUsed || 0).toLocaleString()}</p>`,
    ].join('\n')
  }
};
